import os
import subprocess
from google.cloud import storage

def image_conversion(event, context):
    bucket_name = event['bucket']
    file_name = event['name']
    conversion_options = event.get('attributes', {}).get('conversion_options', '')

    if not file_name.lower().endswith(('.png', '.jpg', '.jpeg', '.gif')):
        print(f"Unsupported file type: {file_name}")
        return

    client = storage.Client()
    bucket = client.bucket(bucket_name)
    blob = bucket.blob(file_name)

    temp_input_file = f"/tmp/{file_name}"
    temp_output_file = f"/tmp/converted_{file_name}"

    blob.download_to_filename(temp_input_file)

    command = ['convert', temp_input_file]
    if conversion_options:
        command.extend(conversion_options.split())
    command.append(temp_output_file)

    try:
        subprocess.call(command, check=True)
        output_blob = bucket.blob(f'converted/{file_name}')
        output_blob.upload_from_filename(temp_output_file)
    except subprocess.CalledProcessError as e:
        print(f"Error during image conversion: {e}")
    finally:
        os.remove(temp_input_file)
        if os.path.exists(temp_output_file):
            os.remove(temp_output_file)